class PaymentSecurityManager(private val context: Context) {
    private val keyStore: KeyStore = KeyStore.getInstance("AndroidKeyStore").apply { load(null) }
    private val MASTER_KEY_ALIAS = "payment_master_key"
    private val PREFERENCE_NAME = "secure_payment_prefs"
    private val prefs = context.getSharedPreferences(PREFERENCE_NAME, Context.MODE_PRIVATE)

    init {
        initializeMasterKey()
    }

    private fun initializeMasterKey() {
        if (!keyStore.containsAlias(MASTER_KEY_ALIAS)) {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                "AndroidKeyStore"
            )
            
            val keyGenParameterSpec = KeyGenParameterSpec.Builder(
                MASTER_KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .build()

            keyGenerator.init(keyGenParameterSpec)
            keyGenerator.generateKey()
        }
    }

    fun encryptCardData(paymentCard: PaymentCard): String {
        val secretKey = keyStore.getKey(MASTER_KEY_ALIAS, null) as SecretKey
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.ENCRYPT_MODE, secretKey)
        
        val cardData = JSONObject().apply {
            put("cardNumber", paymentCard.cardNumber)
            put("cvv", paymentCard.cvv)
            put("expiryMonth", paymentCard.expiryMonth)
            put("expiryYear", paymentCard.expiryYear)
            put("cardHolderName", paymentCard.cardHolderName)
            paymentCard.billingAddress?.let {
                put("billingAddress", JSONObject().apply {
                    put("street", it.street)
                    put("city", it.city)
                    put("state", it.state)
                    put("zipCode", it.zipCode)
                    put("country", it.country)
                })
            }
        }.toString()

        val encryptedData = cipher.doFinal(cardData.toByteArray(Charsets.UTF_8))
        val iv = cipher.iv

        val combined = ByteArrayOutputStream().apply {
            write(iv.size)
            write(iv)
            write(encryptedData)
        }.toByteArray()

        return Base64.encodeToString(combined, Base64.NO_WRAP)
    }

    fun decryptCardData(encryptedData: String): PaymentCard {
        val combined = Base64.decode(encryptedData, Base64.NO_WRAP)
        val ivSize = combined[0].toInt()
        val iv = combined.copyOfRange(1, ivSize + 1)
        val encrypted = combined.copyOfRange(ivSize + 1, combined.size)

        val secretKey = keyStore.getKey(MASTER_KEY_ALIAS, null) as SecretKey
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        val gcmSpec = GCMParameterSpec(128, iv)
        cipher.init(Cipher.DECRYPT_MODE, secretKey, gcmSpec)

        val decryptedData = cipher.doFinal(encrypted)
        val jsonData = JSONObject(String(decryptedData, Charsets.UTF_8))

        val billingAddress = if (jsonData.has("billingAddress")) {
            val addressJson = jsonData.getJSONObject("billingAddress")
            BillingAddress(
                street = addressJson.getString("street"),
                city = addressJson.getString("city"),
                state = addressJson.getString("state"),
                zipCode = addressJson.getString("zipCode"),
                country = addressJson.getString("country")
            )
        } else null

        return PaymentCard(
            cardNumber = jsonData.getString("cardNumber"),
            cvv = jsonData.getString("cvv"),
            expiryMonth = jsonData.getString("expiryMonth"),
            expiryYear = jsonData.getString("expiryYear"),
            cardHolderName = jsonData.getString("cardHolderName"),
            billingAddress = billingAddress
        )
    }

    fun validateCardNumber(cardNumber: String): Boolean {
        val cleaned = cardNumber.replace("\\s".toRegex(), "")
        if (cleaned.length < 13 || cleaned.length > 19) return false
        if (!cleaned.all { it.isDigit() }) return false

        var sum = 0
        var alternate = false
        for (i in cleaned.length - 1 downTo 0) {
            var digit = cleaned[i].toString().toInt()
            if (alternate) {
                digit *= 2
                if (digit > 9) digit -= 9
            }
            sum += digit
            alternate = !alternate
        }
        return sum % 10 == 0
    }

    fun validateCVV(cvv: String): Boolean {
        return cvv.matches(Regex("^\\d{3,4}$"))
    }

    fun validateExpiry(month: String, year: String): Boolean {
        try {
            val expiryMonth = month.toInt()
            val expiryYear = year.toInt()
            
            if (expiryMonth < 1 || expiryMonth > 12) return false
            
            val calendar = Calendar.getInstance()
            val currentYear = calendar.get(Calendar.YEAR) % 100
            val currentMonth = calendar.get(Calendar.MONTH) + 1
            
            if (expiryYear < currentYear) return false
            if (expiryYear == currentYear && expiryMonth < currentMonth) return false
            
            return true
        } catch (e: Exception) {
            return false
        }
    }

    fun maskCardNumber(cardNumber: String): String {
        val cleaned = cardNumber.replace("\\s".toRegex(), "")
        if (cleaned.length < 4) return "****"
        return "**** **** **** ${cleaned.takeLast(4)}"
    }

    fun generateTransactionSignature(transaction: Transaction, secretKey: String): String {
        val data = "${transaction.id}${transaction.amount}${transaction.currency}${transaction.timestamp}${secretKey}"
        val digest = MessageDigest.getInstance("SHA-256")
        val hash = digest.digest(data.toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(hash, Base64.NO_WRAP)
    }
}

class InAppPurchaseManager(private val context: Context) {
    private val transactions = ConcurrentHashMap<String, Transaction>()

    suspend fun processPurchase(
        productId: String,
        amount: BigDecimal,
        currency: String,
        userId: String
    ): PaymentResult = withContext(Dispatchers.IO) {
        try {
            val transaction = Transaction(
                amount = amount,
                currency = currency,
                status = TransactionStatus.PROCESSING,
                merchantId = "in_app_merchant",
                description = "In-app purchase: $productId",
                paymentMethod = PaymentMethod.IN_APP_PURCHASE,
                metadata = mapOf(
                    "productId" to productId,
                    "userId" to userId
                )
            )

            transactions[transaction.id] = transaction

            delay(1000)

            val updatedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
            transactions[transaction.id] = updatedTransaction

            PaymentResult(
                success = true,
                transaction = updatedTransaction
            )
        } catch (e: Exception) {
            Log.e("InAppPurchase", "Purchase failed", e)
            PaymentResult(
                success = false,
                transaction = null,
                errorMessage = e.message,
                errorCode = "IAP_ERROR"
            )
        }
    }

    fun getTransaction(transactionId: String): Transaction? {
        return transactions[transactionId]
    }
}

