class WalletManager(private val context: Context) {
    private val wallets = ConcurrentHashMap<String, WalletBalance>()
    private val securityManager = PaymentSecurityManager(context)

    suspend fun createWallet(userId: String, currency: String): WalletBalance {
        return withContext(Dispatchers.IO) {
            val wallet = WalletBalance(
                userId = userId,
                balance = BigDecimal.ZERO,
                currency = currency
            )
            wallets[userId] = wallet
            wallet
        }
    }

    suspend fun addFunds(
        userId: String,
        amount: BigDecimal,
        paymentCard: PaymentCard
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val wallet = wallets[userId] ?: throw Exception("Wallet not found")
                
                if (amount <= BigDecimal.ZERO) {
                    throw Exception("Amount must be positive")
                }

                if (!securityManager.validateCardNumber(paymentCard.cardNumber)) {
                    throw Exception("Invalid card number")
                }

                wallet.balance = wallet.balance.add(amount)
                wallets[userId] = wallet.copy(lastUpdated = System.currentTimeMillis())

                val transaction = Transaction(
                    amount = amount,
                    currency = wallet.currency,
                    status = TransactionStatus.COMPLETED,
                    merchantId = "wallet_system",
                    description = "Add funds to wallet",
                    paymentMethod = PaymentMethod.WALLET,
                    metadata = mapOf("userId" to userId)
                )

                PaymentResult(success = true, transaction = transaction)
            } catch (e: Exception) {
                Log.e("WalletManager", "Add funds failed", e)
                PaymentResult(
                    success = false,
                    transaction = null,
                    errorMessage = e.message,
                    errorCode = "WALLET_ADD_FUNDS_ERROR"
                )
            }
        }
    }

    suspend fun deductFunds(
        userId: String,
        amount: BigDecimal,
        description: String
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val wallet = wallets[userId] ?: throw Exception("Wallet not found")
                
                if (amount <= BigDecimal.ZERO) {
                    throw Exception("Amount must be positive")
                }

                if (wallet.balance < amount) {
                    throw Exception("Insufficient balance")
                }

                wallet.balance = wallet.balance.subtract(amount)
                wallets[userId] = wallet.copy(lastUpdated = System.currentTimeMillis())

                val transaction = Transaction(
                    amount = amount,
                    currency = wallet.currency,
                    status = TransactionStatus.COMPLETED,
                    merchantId = "wallet_system",
                    description = description,
                    paymentMethod = PaymentMethod.WALLET,
                    metadata = mapOf("userId" to userId)
                )

                PaymentResult(success = true, transaction = transaction)
            } catch (e: Exception) {
                Log.e("WalletManager", "Deduct funds failed", e)
                PaymentResult(
                    success = false,
                    transaction = null,
                    errorMessage = e.message,
                    errorCode = "WALLET_DEDUCT_FUNDS_ERROR"
                )
            }
        }
    }

    fun getBalance(userId: String): WalletBalance? {
        return wallets[userId]
    }

    suspend fun transferFunds(
        fromUserId: String,
        toUserId: String,
        amount: BigDecimal
    ): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val fromWallet = wallets[fromUserId] ?: throw Exception("Source wallet not found")
                val toWallet = wallets[toUserId] ?: throw Exception("Destination wallet not found")

                if (fromWallet.currency != toWallet.currency) {
                    throw Exception("Currency mismatch")
                }

                if (fromWallet.balance < amount) {
                    throw Exception("Insufficient balance")
                }

                fromWallet.balance = fromWallet.balance.subtract(amount)
                toWallet.balance = toWallet.balance.add(amount)

                wallets[fromUserId] = fromWallet.copy(lastUpdated = System.currentTimeMillis())
                wallets[toUserId] = toWallet.copy(lastUpdated = System.currentTimeMillis())

                val transaction = Transaction(
                    amount = amount,
                    currency = fromWallet.currency,
                    status = TransactionStatus.COMPLETED,
                    merchantId = "wallet_system",
                    description = "Transfer between wallets",
                    paymentMethod = PaymentMethod.WALLET,
                    metadata = mapOf(
                        "fromUserId" to fromUserId,
                        "toUserId" to toUserId
                    )
                )

                PaymentResult(success = true, transaction = transaction)
            } catch (e: Exception) {
                Log.e("WalletManager", "Transfer failed", e)
                PaymentResult(
                    success = false,
                    transaction = null,
                    errorMessage = e.message,
                    errorCode = "WALLET_TRANSFER_ERROR"
                )
            }
        }
    }
}

class PaymentGateway(private val context: Context) : PaymentProcessor {
    private val securityManager = PaymentSecurityManager(context)
    private val transactions = ConcurrentHashMap<String, Transaction>()
    private val walletManager = WalletManager(context)

    override suspend fun processPayment(
        amount: BigDecimal,
        currency: String,
        paymentCard: PaymentCard,
        description: String
    ): PaymentResult = withContext(Dispatchers.IO) {
        try {
            if (!securityManager.validateCardNumber(paymentCard.cardNumber)) {
                throw Exception("Invalid card number")
            }

            if (!securityManager.validateCVV(paymentCard.cvv)) {
                throw Exception("Invalid CVV")
            }

            if (!securityManager.validateExpiry(paymentCard.expiryMonth, paymentCard.expiryYear)) {
                throw Exception("Card expired or invalid expiry date")
            }

            if (amount <= BigDecimal.ZERO) {
                throw Exception("Invalid amount")
            }

            val transaction = Transaction(
                amount = amount,
                currency = currency,
                status = TransactionStatus.PROCESSING,
                merchantId = "merchant_default",
                description = description,
                paymentMethod = PaymentMethod.CREDIT_CARD
            )

            transactions[transaction.id] = transaction

            val encryptedCard = securityManager.encryptCardData(paymentCard)
            
            delay(2000)

            val completedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
            transactions[transaction.id] = completedTransaction

            PaymentResult(success = true, transaction = completedTransaction)
        } catch (e: Exception) {
            Log.e("PaymentGateway", "Payment processing failed", e)
            PaymentResult(
                success = false,
                transaction = null,
                errorMessage = e.message,
                errorCode = "PAYMENT_PROCESSING_ERROR"
            )
        }
    }

    override suspend fun processWalletPayment(
        userId: String,
        amount: BigDecimal,
        currency: String,
        description: String
    ): PaymentResult {
        return walletManager.deductFunds(userId, amount, description)
    }

    override suspend fun refundTransaction(transactionId: String): PaymentResult =
        withContext(Dispatchers.IO) {
            try {
                val transaction = transactions[transactionId]
                    ?: throw Exception("Transaction not found")

                if (transaction.status != TransactionStatus.COMPLETED) {
                    throw Exception("Only completed transactions can be refunded")
                }

                val refundTransaction = transaction.copy(
                    id = UUID.randomUUID().toString(),
                    status = TransactionStatus.REFUNDED,
                    timestamp = System.currentTimeMillis(),
                    description = "Refund: ${transaction.description}"
                )

                transactions[refundTransaction.id] = refundTransaction
                transactions[transactionId] = transaction.copy(status = TransactionStatus.REFUNDED)

                PaymentResult(success = true, transaction = refundTransaction)
            } catch (e: Exception) {
                Log.e("PaymentGateway", "Refund failed", e)
                PaymentResult(
                    success = false,
                    transaction = null,
                    errorMessage = e.message,
                    errorCode = "REFUND_ERROR"
                )
            }
        }

    override suspend fun getTransactionStatus(transactionId: String): Transaction? {
        return transactions[transactionId]
    }

    fun getAllTransactions(): List<Transaction> {
        return transactions.values.toList()
    }
}

class PaymentModule(private val context: Context) {
    private val paymentGateway = PaymentGateway(context)
    private val walletManager = WalletManager(context)
    private val inAppPurchaseManager = InAppPurchaseManager(context)
    private val googlePayManager = GooglePayManager(context)
    private val securityManager = PaymentSecurityManager(context)

    suspend fun processCardPayment(
        amount: BigDecimal,
        currency: String,
        paymentCard: PaymentCard,
        description: String
    ): PaymentResult {
        return paymentGateway.processPayment(amount, currency, paymentCard, description)
    }

    suspend fun processWalletPayment(
        userId: String,
        amount: BigDecimal,
        currency: String,
        description: String
    ): PaymentResult {
        return paymentGateway.processWalletPayment(userId, amount, currency, description)
    }

    suspend fun createWallet(userId: String, currency: String = "USD"): WalletBalance {
        return walletManager.createWallet(userId, currency)
    }

    suspend fun addFundsToWallet(
        userId: String,
        amount: BigDecimal,
        paymentCard: PaymentCard
    ): PaymentResult {
        return walletManager.addFunds(userId, amount, paymentCard)
    }

    fun getWalletBalance(userId: String): WalletBalance? {
        return walletManager.getBalance(userId)
    }

    suspend fun transferBetweenWallets(
        fromUserId: String,
        toUserId: String,
        amount: BigDecimal
    ): PaymentResult {
        return walletManager.transferFunds(fromUserId, toUserId, amount)
    }

    suspend fun processInAppPurchase(
        productId: String,
        amount: BigDecimal,
        currency: String,
        userId: String
    ): PaymentResult {
        return inAppPurchaseManager.processPurchase(productId, amount, currency, userId)
    }

    suspend fun refundTransaction(transactionId: String): PaymentResult {
        return paymentGateway.refundTransaction(transactionId)
    }

    suspend fun getTransactionHistory(): List<Transaction> {
        return withContext(Dispatchers.IO) {
            paymentGateway.getAllTransactions()
        }
    }

    fun isGooglePayAvailable(): Boolean {
        return googlePayManager.isGooglePayAvailable()
    }

    fun createGooglePayRequest(
        amount: BigDecimal,
        currency: String,
        merchantName: String
    ): JSONObject {
        return googlePayManager.createPaymentDataRequest(amount, currency, merchantName)
    }

    fun maskCardNumber(cardNumber: String): String {
        return securityManager.maskCardNumber(cardNumber)
    }

    fun validateCard(paymentCard: PaymentCard): Boolean {
        return securityManager.validateCardNumber(paymentCard.cardNumber) &&
                securityManager.validateCVV(paymentCard.cvv) &&
                securityManager.validateExpiry(paymentCard.expiryMonth, paymentCard.expiryYear)
    }
}